import { fetchUsers, fetchUser } from './api.js';
import { isSuccess } from './types.js';

export async function handleGetUsers() {
  const response = await fetchUsers();
  if (!isSuccess(response)) {
    return { error: 'Failed to fetch users', code: response.status };
  }
  return { users: response.data, count: response.data.length };
}

export async function handleGetUser(id) {
  const response = await fetchUser(id);
  if (!isSuccess(response)) {
    return { error: `User ${id} not found`, code: response.status };
  }
  return { user: response.data };
}

