import { handleGetUsers, handleGetUser } from './src/controller.js';
import assert from 'node:assert/strict';

const usersResult = await handleGetUsers();
assert.ok(usersResult.users, 'Should have users array');
assert.equal(usersResult.count, 2);
assert.ok(!usersResult.error, 'Should not have error');

const userResult = await handleGetUser(1);
assert.ok(userResult.user, 'Should have user object');
assert.equal(userResult.user.name, 'Alice');
assert.ok(!userResult.error, 'Should not have error for existing user');

const missingResult = await handleGetUser(999);
assert.ok(missingResult.error, 'Should have error for missing user');
assert.equal(missingResult.code, 404);

console.log('All tests passed');
